	// Wired fully in Task 8 after bpf2go generates the typed map accessors.
	slog.Debug("ebpf/observability: collect tick")
}

// Close stops the collector. Implements io.Closer.
func (c *Collector) Close() error {
	select {
	case <-c.stop:
	default:
		close(c.stop)
	}
	return nil
}

