// LPMKey mirrors the C struct bpf_lpm_trie_key + 4-byte IPv4 data.
type LPMKey struct {
	Prefixlen uint32
	Addr      [4]byte
}

// XDPObjects holds the bpf2go-generated map handles. Nil = no eBPF objects loaded.
