    u64 len = ctx->len;
    u64 *val = bpf_map_lookup_elem(&net_bytes_in, &pid);
    if (val)
        __sync_fetch_and_add(val, len);
    else
        bpf_map_update_elem(&net_bytes_in, &pid, &len, BPF_ANY);
