#define AUDIT_TCP     2
#define AUDIT_CONNECT 3

struct audit_event {
    __u8  type;
    __u32 pid;
    __u32 ppid;
    __u64 timestamp_ns;
    char  comm[TASK_COMM_LEN];
    union {
        struct {
            char path[PATH_LEN];
        } exec;
        struct {
            __be32 saddr;
            __be32 daddr;
            __be16 sport;
            __be16 dport;
        } net;
    };
};

// Ring buffer for audit events
