package xdp

import (
    "encoding/binary"
    "fmt"
    "net"
)

// LPMKey mirrors the C struct bpf_lpm_trie_key + 4-byte IPv4 data.
type LPMKey struct {
    Prefixlen uint32
    Addr      [4]byte
}

// parseLPMKey parses a CIDR string into an LPMKey for the BPF LPM trie.
func parseLPMKey(cidr string) (LPMKey, error) {
