```

**Fix 1c: Ring buffer comment** (lines 39-43)
Update the comment:
```c
// Ring buffer for audit events.
// max_entries is fixed at compile time. Userspace overrides via AuditRingBufferSize
// when creating the ring reader or by resizing the map at load time (LoadCollection).
```

### 2. `internal/ebpf/programs/observability.c`

**Fix 2a: sched_switch — delta computation** (lines 51-64)
Add a `last_runtime_map` and compute deltas instead of accumulating raw values:

```c
// Last observed sum_exec_runtime per TGID (for delta computation)
struct {
    __uint(type, BPF_MAP_TYPE_HASH);
    __uint(max_entries, 4096);
    __type(key, u32);
    __type(value, u64);
} last_runtime_map SEC(".maps");

// sched_switch: accumulate prev task CPU time delta
SEC("tp_btf/sched_switch")
int BPF_PROG(handle_sched_switch, bool preempt,
             struct task_struct *prev, struct task_struct *next)
{
    u32 tgid = BPF_CORE_READ(prev, tgid);
    u64 runtime = BPF_CORE_READ(prev, se.sum_exec_runtime);

    u64 *last = bpf_map_lookup_elem(&last_runtime_map, &tgid);
    u64 delta = last ? (runtime - *last) : 0;
    bpf_map_update_elem(&last_runtime_map, &tgid, &runtime, BPF_ANY);

    if (delta > 0) {
        u64 *val = bpf_map_lookup_elem(&cpu_time_map, &tgid);
        if (val)
